memory = []

def update_memory(message: str, role: str):
    memory.append({"role": role, "content": message})
    if len(memory) > 10:
        memory.pop(0)  # Limit history

memory_agent = AssistantAgent(
    name="MemoryManager",
    llm_config=llm_config,
    system_message="Summarize and inject relevant conversation history."
)
def get_context() -> str:
    return "\n".join([f"{m['role']}: {m['content']}" for m in memory[-5:]])
memory_agent.register_for_llm(name="get_history")(get_context)

