conversation_state = []

def loop_protection_filter(reply: str, context: dict) -> bool:
    conversation_state.append(reply)
    if len(conversation_state) > 20:
        cycle_score = vex_client.verify_loop_detection(conversation_state[-10:])
        if cycle_score > 0.8:
            return False  # Block reply
    return True

manager.register_reply_filter(loop_protection_filter)
retrieval_agent.register_reply_filter(loop_protection_filter)

@vex_client.register_filter(verifications=["pii-protection", "safety-filtering"])
def safety_filter(reply: str, context: dict) -> str:
    verification = vex_client.verify(
        text=reply,
        rules={
            "no_pii": True,
            "no_harmful_content": True,
            "no_hallucinations": {"ground_truth": context["retrieved_docs"]}
        }
    )
    if verification.is_valid:
        return reply
    else:
        return "Sorry, I can't respond to that due to safety guidelines."  # Fallback

response_agent.reply_filter = safety_filter

